args.sparql:
SELECT ?director ?directorLabel WHERE {
  VALUES (?writer ?costumeDesigner) { (wd:Q238638 wd:Q289952) }

  # Find films written by Chris Weitz and designed by Sandy Powell
  ?film wdt:P58 ?writer ;
        wdt:P840 ?costumeDesigner ;
        wdt:P577 ?releaseDate .

  # Extract release year and calculate ceremony year
  BIND(YEAR(?releaseDate) AS ?filmYear)
  BIND(?filmYear + 1 AS ?awardsYear)

  # Find the corresponding Academy Awards ceremony
  ?ceremony wdt:P31 wd:Q1792579 ;  # Award ceremony
            wdt:P179 wd:Q2025051 ;  # Academy Awards series
            wdt:P585 ?ceremonyDate .
  FILTER(YEAR(?ceremonyDate) = ?awardsYear)

  # Director of the ceremony
  ?ceremony wdt:P2534 ?director .

  # Get English labels for results
  OPTIONAL { ?director rdfs:label ?directorLabel FILTER (LANG(?directorLabel) = 'en') }
}
LIMIT 10
